import { AgentResponse, AppData, CustomElement, ValidationScores } from '../types';

export const transformJsonToSlateNodes = (data: AppData): CustomElement[] => {
  const nodes: CustomElement[] = [];

  // 1. Title
  nodes.push({
    type: 'heading-one',
    children: [{ text: 'User Stories Import' }],
  });

  nodes.push({
    type: 'paragraph',
    children: [{ text: 'The following data has been parsed from the attached JSON source.' }],
  });

  // 2. Transform User Stories
  try {
    const rawResponse = data.data.UserStory_Agent.response;
    if (rawResponse) {
      const parsedStories: AgentResponse = JSON.parse(rawResponse);

      nodes.push({
        type: 'heading-two',
        children: [{ text: 'Detailed User Stories' }],
      });

      // Create Table Header
      const tableHeaderRow: CustomElement = {
        type: 'table-row',
        children: [
          { type: 'table-cell', header: true, children: [{ text: 'Category' }] },
          { type: 'table-cell', header: true, children: [{ text: 'Req ID' }] },
          { type: 'table-cell', header: true, children: [{ text: 'Story ID' }] },
          { type: 'table-cell', header: true, children: [{ text: 'User Story' }] },
          { type: 'table-cell', header: true, children: [{ text: 'Type' }] },
        ],
      };

      const tableRows: CustomElement[] = [tableHeaderRow];

      // Flatten data for table
      Object.entries(parsedStories).forEach(([category, reqData]) => {
        if (reqData.UserStories && Array.isArray(reqData.UserStories)) {
          reqData.UserStories.forEach((story) => {
            tableRows.push({
              type: 'table-row',
              children: [
                { type: 'table-cell', children: [{ text: category }] },
                { type: 'table-cell', children: [{ text: reqData.req_id || '-' }] },
                { type: 'table-cell', children: [{ text: story.userstory_id || '-' }] },
                { type: 'table-cell', children: [{ text: story.Story || '-' }] },
                { type: 'table-cell', children: [{ text: story.RequirementType || '-' }] },
              ],
            });
          });
        }
      });

      nodes.push({
        type: 'table',
        children: tableRows as any, 
      });
    }
  } catch (e) {
    console.error("Failed to parse User Stories", e);
    nodes.push({
      type: 'paragraph',
      children: [{ text: 'Error parsing User Story data.' }],
    });
  }

  // 3. Transform Validity Scores
  try {
    const rawScores = data.data.UserStoryValidityScorer_Agent.response;
    if (rawScores) {
      const parsedScores: ValidationScores = JSON.parse(rawScores);

      nodes.push({
        type: 'heading-two',
        children: [{ text: 'Validity Scores' }],
      });

       const scoreHeaderRow: CustomElement = {
        type: 'table-row',
        children: [
          { type: 'table-cell', header: true, children: [{ text: 'Metric' }] },
          { type: 'table-cell', header: true, children: [{ text: 'Score' }] },
        ],
      };

      const scoreRows: CustomElement[] = [scoreHeaderRow];

      Object.entries(parsedScores).forEach(([metric, score]) => {
        if (metric !== 'Justification') { // Skip complex objects/nulls for simple table
             scoreRows.push({
              type: 'table-row',
              children: [
                { type: 'table-cell', children: [{ text: metric }] },
                { type: 'table-cell', children: [{ text: String(score) }] },
              ],
            });
        }
      });

      nodes.push({
        type: 'table',
        children: scoreRows as any,
      });
    }

  } catch (e) {
    console.error("Failed to parse Scores", e);
    nodes.push({
        type: 'paragraph',
        children: [{ text: 'Error parsing Validity Scores.' }],
      });
  }

  // Add trailing paragraph so user can type after table
  nodes.push({
    type: 'paragraph',
    children: [{ text: '' }],
  });

  return nodes;
};

import React from 'react';
import { RenderElementProps, RenderLeafProps } from 'slate-react';

export const Element = (props: RenderElementProps) => {
  const { attributes, children, element } = props;

  switch (element.type) {
    case 'heading-one':
      return (
        <h1 {...attributes} className="text-3xl font-bold mb-4 mt-6 text-slate-800">
          {children}
        </h1>
      );
    case 'heading-two':
      return (
        <h2 {...attributes} className="text-2xl font-semibold mb-3 mt-6 text-slate-700">
          {children}
        </h2>
      );
    case 'table':
      return (
        <div className="overflow-x-auto my-4 border rounded-lg border-slate-200 shadow-sm">
          <table {...attributes} className="w-full text-sm text-left text-slate-600 bg-white">
            <tbody className="divide-y divide-slate-200">
                {children}
            </tbody>
          </table>
        </div>
      );
    case 'table-row':
      return (
        <tr {...attributes} className="hover:bg-slate-50 transition-colors">
          {children}
        </tr>
      );
    case 'table-cell':
      const isHeader = (element as any).header;
      if (isHeader) {
        return (
            <th {...attributes} className="px-6 py-3 font-semibold text-slate-800 bg-slate-100 border-b border-slate-200 select-none">
                {children}
            </th>
        );
      }
      return (
        <td {...attributes} className="px-6 py-4 border-slate-100 border-r last:border-r-0 align-top">
          {children}
        </td>
      );
    case 'paragraph':
    default:
      return (
        <p {...attributes} className="mb-2 text-slate-700 leading-relaxed">
          {children}
        </p>
      );
  }
};

export const Leaf = ({ attributes, children, leaf }: RenderLeafProps) => {
  if (leaf.bold) {
    children = <strong>{children}</strong>;
  }

  if (leaf.italic) {
    children = <em>{children}</em>;
  }

  return <span {...attributes}>{children}</span>;
};

import React from 'react';
import { useSlate } from 'slate-react';
import { Editor, Transforms, Text, Element as SlateElement } from 'slate';
import { Bold, Italic, Type, Heading1, Heading2 } from 'lucide-react';

const Button = ({ active, children, onMouseDown }: any) => (
  <button
    onMouseDown={onMouseDown}
    className={`p-2 rounded hover:bg-slate-200 transition-colors ${
      active ? 'text-blue-600 bg-blue-50' : 'text-slate-600'
    }`}
  >
    {children}
  </button>
);

const Toolbar = () => {
  const editor = useSlate();

  const isMarkActive = (editor: Editor, format: string) => {
    const marks = Editor.marks(editor);
    return marks ? (marks as any)[format] === true : false;
  };

  const toggleMark = (editor: Editor, format: string) => {
    const isActive = isMarkActive(editor, format);
    if (isActive) {
      Editor.removeMark(editor, format);
    } else {
      Editor.addMark(editor, format, true);
    }
  };

  const isBlockActive = (editor: Editor, format: string) => {
    const { selection } = editor;
    if (!selection) return false;

    const [match] = Array.from(
      Editor.nodes(editor, {
        at: Editor.unhangRange(editor, selection),
        match: (n) =>
          !Editor.isEditor(n) && SlateElement.isElement(n) && (n as any).type === format,
      })
    );

    return !!match;
  };

  const toggleBlock = (editor: Editor, format: string) => {
    const isActive = isBlockActive(editor, format);
    Transforms.setNodes(
      editor,
      { type: isActive ? 'paragraph' : format } as Partial<SlateElement>,
    );
  };

  return (
    <div className="flex items-center gap-1 p-2 border-b border-slate-200 bg-slate-50 sticky top-0 z-10">
      <Button
        active={isMarkActive(editor, 'bold')}
        onMouseDown={(event: any) => {
          event.preventDefault();
          toggleMark(editor, 'bold');
        }}
      >
        <Bold size={18} />
      </Button>
      <Button
        active={isMarkActive(editor, 'italic')}
        onMouseDown={(event: any) => {
          event.preventDefault();
          toggleMark(editor, 'italic');
        }}
      >
        <Italic size={18} />
      </Button>
      <div className="w-px h-6 bg-slate-300 mx-2" />
      <Button
        active={isBlockActive(editor, 'heading-one')}
        onMouseDown={(event: any) => {
          event.preventDefault();
          toggleBlock(editor, 'heading-one');
        }}
      >
        <Heading1 size={18} />
      </Button>
      <Button
        active={isBlockActive(editor, 'heading-two')}
        onMouseDown={(event: any) => {
          event.preventDefault();
          toggleBlock(editor, 'heading-two');
        }}
      >
        <Heading2 size={18} />
      </Button>
      <Button
        active={isBlockActive(editor, 'paragraph')}
        onMouseDown={(event: any) => {
          event.preventDefault();
          toggleBlock(editor, 'paragraph');
        }}
      >
        <Type size={18} />
      </Button>
    </div>
  );
};

export default Toolbar;

import React, { useMemo, useState, useCallback } from 'react';
import { createEditor, Descendant } from 'slate';
import { Slate, Editable, withReact } from 'slate-react';
import { withHistory } from 'slate-history';
import { Element, Leaf } from './Elements';
import Toolbar from './Toolbar';
import { CustomEditor } from '../../types';

interface SlateEditorProps {
  initialValue: Descendant[];
}

const SlateEditor: React.FC<SlateEditorProps> = ({ initialValue }) => {
  const editor = useMemo(() => withHistory(withReact(createEditor() as CustomEditor)), []);
  // We need to manage state here, but since initialValue comes from props which might change only on reset,
  // we can use it to initialize. If the parent updates initialValue to *change* content dynamically after mount,
  // we would need a useEffect to reset the editor children.
  // For this demo, we assume initialValue is stable or we want to re-mount on change.

  const [value, setValue] = useState<Descendant[]>(initialValue);

  const renderElement = useCallback((props: any) => <Element {...props} />, []);
  const renderLeaf = useCallback((props: any) => <Leaf {...props} />, []);

  return (
    <div className="border border-slate-300 rounded-lg shadow-sm bg-white overflow-hidden flex flex-col h-full">
      <Slate 
        editor={editor} 
        initialValue={initialValue} 
        onChange={(val) => setValue(val)}
      >
        <Toolbar />
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
            <Editable
            renderElement={renderElement}
            renderLeaf={renderLeaf}
            placeholder="Start typing..."
            className="outline-none min-h-[500px]"
            spellCheck
            autoFocus
            />
        </div>
      </Slate>
    </div>
  );
};

export default SlateEditor;

