}

const SlateEditor: React.FC<SlateEditorProps> = ({ initialValue }) => {
  const editor = useMemo(() => withHistory(withReact(createEditor() as CustomEditor)), []);
  // We need to manage state here, but since initialValue comes from props which might change only on reset,
  // we can use it to initialize. If the parent updates initialValue to *change* content dynamically after mount,
  // we would need a useEffect to reset the editor children.
  // For this demo, we assume initialValue is stable or we want to re-mount on change.

  const [value, setValue] = useState<Descendant[]>(initialValue);

  const renderElement = useCallback((props: any) => <Element {...props} />, []);
  const renderLeaf = useCallback((props: any) => <Leaf {...props} />, []);

  const handleShowData = () => {
    alert(JSON.stringify(value, null, 2));
  };

  return (
    <div className="flex flex-col h-full gap-4">
      <div className="flex justify-end">
         <button 
            onClick={handleShowData}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 transition-all shadow-sm"
         >
            <Eye size={16} />
            Show Data
         </button>
      </div>
      <div className="border border-slate-300 rounded-lg shadow-sm bg-white overflow-hidden flex flex-col flex-1">
        <Slate 
          editor={editor} 
          initialValue={initialValue} 
          onChange={(val) => setValue(val)}
        >
          <Toolbar />
          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
              <Editable
              renderElement={renderElement}
              renderLeaf={renderLeaf}
              placeholder="Start typing..."
              className="outline-none min-h-[500px]"
              spellCheck
              autoFocus
              />
          </div>
        </Slate>
      </div>
    </div>
  );
};

export default SlateEditor;

